function dirtyFound($this,$item)
{
	BootstrapDialog.show({
		animate: false,
		closable: false,
		type: BootstrapDialog.TYPE_WARNING,
		title: 'Discard Changes?',
		message: function(dialog) {
			return $('<div>'+window.lang.translate("Leaving this page will discard any unsaved changes.")+'</br></br><b>'+window.lang.translate("Are you sure you want to continue?")+'</b></div>');
		},
		buttons: [
		{
			id: 'btn-dirty',
			label: 'Yes',
			cssClass: 'btn-warning',
			action: function(modalRef) {
				parent.initialObject();
				if( typeof $this !== 'undefined' && $.isFunction($this))
					$this();
				else
					$($this).trigger('click');
				modalRef.close();
			}
		},
		{
			cssClass: 'btn-default closebtn',
			label: "Close",
			action: function (modalRef) {
				$('.notfound').text('Highlighted name are unsaved changes.').removeClass('hide').addClass('tat-has-warning');
				$('.page-content-wrapper form').find('.tat-warning').removeClass('tat-warning');
				$.each($item, function(iK)
				{
					$('.page-content-wrapper form [name="'+iK+'"]').closest('.row').find(':first').addClass('tat-warning');
				});
				setTimeout(function(){
				modalRef.close();
				},100);
			}
		}
		]
	});
}
function initialObject($this)
{
	parent.$('#initdiv').empty();
	if( $('.page-content-wrapper form').length )
	{
		var a = $('.page-content-wrapper form').serializeArray();
		var div = parent.$('#initdiv')[0];
		$.each(a, function(){
			$.data(div,this.name, $.trim(this.value));
		});
	}
};
function dirtyObject()
{
	if( $('.page-content-wrapper form').length )
	{
		var o = {};
		var a = $('.page-content-wrapper form').serializeArray();
		var div = parent.$('#initdiv')[0];
		$.each(a, function() {
			 if($.trim(this.value)!=$.data(div,this.name)){
				if (o[this.name]) {
					if (!o[this.name].push) {
						o[this.name] = [o[this.name]];
					}
					o[this.name].push({oldVal:$.data(div,this.name),newVal:this.value});
				} else {
					o[this.name] = {oldVal:$.data(div,this.name),newVal:this.value};
				}
			 }
		});
		return o;
	}
	else
		return false;
};
function b64toBlob(b64Data, contentType, sliceSize) {
    contentType = contentType || '';
    sliceSize = sliceSize || 512;

    var byteCharacters = atob(b64Data);
    var byteArrays = [];

    for (var offset = 0; offset < byteCharacters.length; offset += sliceSize) {
        var slice = byteCharacters.slice(offset, offset + sliceSize);

        var byteNumbers = new Array(slice.length);
        for (var i = 0; i < slice.length; i++) {
            byteNumbers[i] = slice.charCodeAt(i);
        }

        var byteArray = new Uint8Array(byteNumbers);

        byteArrays.push(byteArray);
    }

    var blob = new Blob(byteArrays, {type: contentType});
    return blob;
}
function SaveToDisk(fileUrl, fileName) {
	parent.vibrate(10);
	var hyperlink = document.createElement('a');
	if ( /chrom(e|ium)/i.test(navigator.userAgent.toLowerCase()) ) // bug fixed in chrome with large data
	{
		var contentType = fileUrl.substr(0, fileUrl.indexOf('base64,'));
		var b64Data = fileUrl.replace( fileUrl.substr(0, fileUrl.indexOf('base64,')), "");
		b64Data = b64Data.replace("base64,","");
		var blob = b64toBlob(b64Data, contentType);
		fileUrl = (window.URL || window.webkitURL).createObjectURL(blob);
	}
    hyperlink.href = fileUrl;
    hyperlink.target = '_blank';
    hyperlink.download = fileName || fileUrl;
    var mouseEvent = new MouseEvent('click', {
        view: window,
        bubbles: true,
        cancelable: true
    });
    hyperlink.dispatchEvent(mouseEvent);
    (window.URL || window.webkitURL).revokeObjectURL(hyperlink.href);
}
function callbackProgress (e) {
  if (typeof e !=='undefined' && e.lengthComputable) {
  	var percentComplete = Math.round(e.loaded / e.total *100);
	$('.progress-bar').html("Please wait... "+percentComplete+"%");
  } else {
	  $('.progress-bar').html("Please wait...");
  }
}
function callbackback(e)
{
	parent.$('.FixedHeader_Cloned').hide();
	var state = (e.state)? e.state:null;
	if(state && state.url != state.curl)
		onload();
	else
	{
		if( $('.breadcrumb li').length <= 2 )
			$('.breadcrumb').find('.itoggleCrumb').trigger('click'); 
		else if( $('.breadcrumb li').length > 2 )
			$('.breadcrumb li:nth-last-child(2)').find('.toggleCrumb').trigger('click');
		else
			onload();
	}
}

function callbackResize()
{
	if ($(window).width() < 767)
	{
		$('#menu-content').removeClass('in').addClass('out');
		$(".page-content-wrapper").css("min-height", $(window).height() - 10 );
	}
	else
	{
		$('#menu-content').removeClass('out').addClass('in');
		$(".page-content-wrapper").css("min-height", $(window).height());
	}
}
function loadsub($sub, $loaddone)
{
	$('.body-tat-content,.body-tat-content-sub').css('visibility','hidden');
	var iload = (typeof $loaddone === "undefined")?loaddone:"";
	
	if( $sub ){
		parent.$('.FixedHeader_Cloned').hide();
		loading();
		$('.body-tat-content').load($sub, iload);
	}
}
function loading($body)
{
	var $body = $body || "yes"; 
	if( $body == "yes")	$('.body-tat-content,.body-tat-content-sub').css('visibility','hidden');
	$('.spinner').removeClass('hide');
	$('.notfound').addClass('hide');
	return false;
}
function unloading(notfound)
{
	$('.body-tat-content,.body-tat-content-sub').css('visibility','visible');
	$('.spinner').addClass('hide');
	$('.notfound').addClass('hide');
	setTimeout(function(){waitingDialog.hide();}, 100);
	var notfound = notfound || "";
	if(notfound ){
		$('.notfound').removeClass('hide');
	}
	return false;
}
function loaddone()
{
	$('.spinner').addClass('hide');
	$('.notfound').addClass('hide');
	setTimeout(function(){waitingDialog.hide();}, 100);
	$('.body-tat-content,.body-tat-content-sub').css('visibility','visible');
	return false;	
}
function toggelMenu($this)
{
	var $this = $($this);
	var href = $this.find('a').attr('href');
	$this.closest('ul').find('li').removeClass('active');
	$this.addClass('active'); 
}
function required($this)
{
	var error =0;
	parent.loaddone();
	$('.page-content-wrapper form').find('.tat-warning,.tat-has-warning').removeClass('tat-warning');
	$('[required]', $this).each(function () {
		var self = $(this);
		
		if( $.trim(self.val()) == "" ){
			error++;
			
			if( typeof(self[0].selectize) !== 'undefined' && Object.keys(self[0].selectize).length !=0  )
				$(self).parent().find('.selectize-control .selectize-input').addClass('br-red');
			else
				self.addClass('br-red');	
			/*msgModal.setTitle("Warning");
			msgModal.setType(BootstrapDialog.TYPE_WARNING);
			msgModal.setData("id",self);
			msgModal.setData("set",true);
			msgModal.setData("msg","Missing");
			msgModal.setData("code",encodeURIComponent(self.attr('placeholder')));
			if( typeof(self[0].selectize) !== 'undefined' && Object.keys(self[0].selectize).length !=0  ) msgModal.setData("id",'.selectize-input input[placeholder="'+self.attr('placeholder')+'"]');
			msgModal.realize();
			msgModal.open();
			return false;*/
		}
	});
	if ( error != 0 )
	{
		msgModal.setTitle(window.lang.translate("Warning"));
		msgModal.setType(BootstrapDialog.TYPE_WARNING);
		msgModal.setData("id",'');
		msgModal.setData("set",true);
		msgModal.setData("msg",window.lang.translate("Missing required field"));
		msgModal.setData("code","");
		msgModal.realize();
		msgModal.open();
		return true;
	}
	else return false;
}
function eAdvanceSearch()
{
	parent.$('.advanceSearch').removeClass("disabled").css('opacity',"1");
}
function dAdvanceSearch()
{
	parent.$('.advanceSearch').addClass("disabled").css('opacity',"0.25");	
}
function mainlink()
{
	var mainlink = document.createElement('a');
	mainlink.className = "toggle";
	mainlink.dataset.togglePanel = "false";
	mainlink.dataset.toggleWhat = ".page-content-wrapper";
	mainlink.dataset.toggleType = "asset-List-View.html";
	var mouseEvent = new Event('assetSearch');
	mainlink.addEventListener('assetSearch', function (e) { parent.toggle(this); }, false);
	mainlink.dispatchEvent(mouseEvent);
	parent.urltoggle();	
}
function mainSearch()
{
	parent.$('.mainSearch').unbind().typeahead('destroy');
	parent.$('.mainSearch').typeahead({
		minLength: 1  
		},{
		name: 'mainSearch',
		displayKey: 'label',
		source: function mainSearchSource(query, process) {
			var item = [];
			var label = (query.toLowerCase().indexOf("asset:") === 0)?query:"Asset: "+query;
			item.push({id:query, label:label});	
			process( item );
		},
		 updater : function(item){
			return item;
		}
	})
	.on('keypress',function(e){
		if(e.which == 13 && !$('.advanceSearch').hasClass('disabled') ) {
			parent.loading();
			$('.clearbtn').trigger('click');	
			$('.searchbtn').trigger('click');
			$(this).trigger('blur');
			$(this).focus();
			return false;
		}
	})
	.on('typeahead:selected', function (e, data) {
		e.preventDefault();
		var dirty = parent.dirtyObject();
		if( dirty != false && Object.keys(dirty).length != 0 )
		{
			parent.dirtyFound(mainlink,dirty);
			return false;
		}
		else
			mainlink();
		
	});	
}
/* WEB API */
var sessionTimeout;
function reLogin(modalRef,uName,uPass,uInstant,iReload){
	$.ajax({
		type: "POST",
		url: "user/PostLogin",
		data: JSON.stringify({"username":uName,"password":uPass,"instantid":uInstant}),
		contentType: "application/json; charset=utf-8",
		dataType: "json",
		async: false,
		success: function($data){
			if($data.__LOGIN__ == 'success')
			{
				if( iReload )
				{
					window.location.href = window.location.origin+"/User/Login";
				}
				else
				{
					parent.msgModal.setTitle(window.lang.translate("Success"));
					parent.msgModal.setType(BootstrapDialog.TYPE_SUCCESS);
					parent.msgModal.setData("id",'');
					parent.msgModal.setData("set",true);
					parent.msgModal.setData("msg",window.lang.translate("Welcome back")+", <b>"+uName+"</b>");
					parent.msgModal.setData("code",'');
					parent.msgModal.realize();
					parent.msgModal.open();
					sessionCheck();
				}
				modalRef.close();		
			}
			else if( $data.__Error__)
			{
				parent.__ERROR__($data);
			}
		}, 
		error: function (XMLHttpRequest, textStatus, errorThrown) { debugger; }
	});	
}
function sessionCheck() {
	$.ajax({
		type: "GET",
		url: "main/GetLoginInfo",
		data: {},
		contentType: "application/json; charset=utf-8",
		dataType: "json",
		async: false,
		success: function($data,e){
			clearTimeout(sessionTimeout);
			if( $data.UserId != null && $data.Username != null  )
			{
				sessionTimeout = setTimeout(sessionCheck, 1800000); // 1800000 = 30 mins
			}
			else
			{
				BootstrapDialog.show({
					type: BootstrapDialog.TYPE_DANGER,
					title: 'Session has been expired...',
					message: $('<div></div>').load('reLogin.html'),
					animate: false,
					closable: false,
					buttons: [
					{
						id: 'submitLogin',
						cssClass: 'btn-primary',
						label: "Submit",
						action: function (modalRef) {
							if( required($('.modal-tat-login')) ) return false;
							
							var oName = parent.$('.username-tat').text();
							var oInstant = parent.$('.instant-tat').text();
							var uName = parent.$('input[name="login-username"]').val();
							var uPass = parent.$('input[name="login-password"]').val();
							var uInstant = parent.$('select[name="instantid"]').val();
							if( oName != uName || oInstant != uInstant )
							{
								parent.msgModal.setTitle(window.lang.translate("Warning"));
								parent.msgModal.setType(BootstrapDialog.TYPE_WARNING);
								parent.msgModal.setData("id",'');
								parent.msgModal.setData("set",true);
								parent.msgModal.setData("msg",window.lang.translate("You are trying to login as different user/instance from the previous login.")+"</br>"+window.lang.translate("All pages will be reload and previous page will be loss.")+"</br></br><b>"+window.lang.translate("Are you sure you want to continue?")+"</b>");
								parent.msgModal.setData("code",'');
								parent.msgModal.realize();
								var btn = parent.msgModal.getButton('msgbtn');
								btn.removeClass('hide').addClass('btn-warning');
								btn.click({}, function(event)
								{
									parent.msgModal.close();
									parent.reLogin(modalRef,uName,uPass,uInstant,true);
								});
								parent.msgModal.open();
								return false;
							}
							else
							{
								parent.reLogin(modalRef,uName,uPass,uInstant,false);
							}
						}
					}]
				});
			}
		}, 
		error: function (XMLHttpRequest, textStatus, errorThrown) { debugger; }
	});
}

function getData($url,$callback,$data,$async)
{ 
	sessionCheck();
	var data = ( typeof $data === "undefined" )? "{}":$data;
	var async = ( typeof $async === "undefined" )? false:$async;
	$.ajax({
		type: "GET",
		url: $url,
		data: data,
		contentType: "application/json; charset=utf-8",
		dataType: "json",
		async: async,
		success: $callback, 
		xhr: function(){
			var xhr = new window.XMLHttpRequest();
			xhr.upload.addEventListener("progress", function(evt){
				   callbackProgress(evt);
			}, false);
			xhr.addEventListener("progress", function(evt){
				   callbackProgress(evt);
			}, false);
			return xhr;
		},
		error: function (XMLHttpRequest, textStatus, errorThrown) { debugger; }
	});
}
function postData($url,$callback,$data,$async)
{
	sessionCheck();
	var data = ( typeof $data === "undefined" )? "{}":$data;
	var async = ( typeof $async === "undefined" )? false:$async;
	$.ajax({
		type: "POST",
		url: $url,
		data: JSON.stringify(data),
		contentType: "application/json; charset=utf-8",
		dataType: "json",
		async: async,
		success: $callback, 
		xhr: function(){
			var xhr = new window.XMLHttpRequest();
			xhr.upload.addEventListener("progress", function(evt){
				  callbackProgress(evt);
			}, false);
			xhr.addEventListener("progress", function(evt){
				   callbackProgress(evt);
			}, false);
			return xhr;
		},
		error: function (XMLHttpRequest, textStatus, errorThrown) { debugger; }
	});
}
function getAccess()
{
	$.ajax({
		url: "../js/role.access.min.js",
		dataType: "script",
		async: false,
		error: function (XMLHttpRequest, textStatus, errorThrown) { debugger; }
	});	
}

function vibrate(count){
	navigator.vibrate = navigator.vibrate || navigator.webkitVibrate || navigator.mozVibrate || navigator.msVibrate;
	var count = count || 0;
	navigator.vibrate(count);
}
function connection()
{
	navigator.connection = navigator.connection || navigator.mozConnection || navigator.webkitConnection || null;
	var connection = {
		type : navigator.connection.type,
		downlinkMax :navigator.connection.downlinkMax,
	};
}
function netStat(event)
{
	if( event.type == "offline" || ( event.type == "click" && navigator.onLine == false ) )
	{
		parent.vibrate(100);
		$('.notfound').text("No Internet Connection").removeClass('hide').addClass('offline');
		$('.spinner').addClass('hide');
	}//else
		//$('.notfound').text("").removeClass('offline').addClass('hide');		
}
