$(window.document).on('keyup','[required],.required input',function(e){
	e.preventDefault();
	if( $.trim($(this).val()) != "" && $(this).closest('div').hasClass('selectize-input') )
		$(this).closest('div.selectize-input').removeClass('br-red');
	else if( $.trim($(this).val()) != "" )
		$(this).removeClass('br-red');
	isError();
});
