$(document).ready(function () 
{
	onload();
	$("#filter-panel")
	.load("../pages/searchDefault.html")
	.on('click',function(e){
		e.preventDefault();
		return false;
	});
	
	$(this).unbind('keypress');
	$(this).on('keypress',function(e){
		if(e.altKey && e.which == 97 ) {
			$('.advanceSearch').trigger('click');
			$('#filter-panel').find('.filter:first').focus();
    	}
		else if(e.altKey && e.which == 99 ) {
			$('.clearbtn').trigger('click');	
		}
	});
	$('#filter-panel').on('keypress','.form-control',function(e){
		if(e.which == 13) {
        	$('.searchbtn').trigger('click');
    	}
	});
	$('.advanceSearch').on('click',function(){
		$('.smHasTheWords').val( $.trim(parent.$('.mainSearch.tt-input').val()) );
	});
	
	var firstDate  = new Date($('.updateddate-tat').text());
	var secondDate = new Date($('.currentdate-tat').text());
	var oneDay = 24*60*60*1000; // hours*minutes*seconds*milliseconds
	var diffDays = Math.round(Math.abs((firstDate.getTime() - secondDate.getTime())/(oneDay)));
	if( parseFloat(diffDays) > 169 )
	{
		var daysCount = ( 180 - parseFloat(diffDays));
		parent.msgModal.setTitle(window.lang.translate("Warning"));
		parent.msgModal.setType(BootstrapDialog.TYPE_WARNING);
		parent.msgModal.setData("id",'');
		parent.msgModal.setData("set",true);
		parent.msgModal.setData("code",(daysCount > 1)?daysCount+" days":daysCount+" day");
		parent.msgModal.setData("msg",window.lang.translate("Required to change your password within"));
		parent.msgModal.realize();
		var btn = parent.msgModal.getButton('msgbtn');
		btn.removeClass('hide').addClass('btn-warning').text('Change Password');
		btn.click({}, function(event)
		{
			$('.change-password-toggle').trigger('click');
			parent.msgModal.close();	
		});
		parent.msgModal.open();	
	}
	
	$.ajaxSetup ({ cache: false	});
	
});
